/* selectVehicleRelationList */ SELECT MVH.VOWNKEY, MVH.VEHICKY, MVH.VHCSNAM, MVH.VHCFNAM, MVH.DRVERNM FROM ${userData.commonSchema}.MVHCMA MVH INNER JOIN ${userData.commonSchema}.MVOWMA MVO ON (MVO.VOWNKEY = MVH.VOWNKEY) INNER JOIN ${userData.schema}.MCODEM MC1 ON MVH.VHCTYPE = MC1.COMCDVL AND MC1.COMCDKY = 'VHCTYPE'
AND MC1.COMCDSY = #{param.comcdsy}
AND MC1.COMCDSY = 'N'
INNER JOIN ${userData.schema}.MCODEM MC2 ON MVH.VHCTNCD = MC2.COMCDVL AND MC2.COMCDKY = 'VHCTNCD'
AND MC2.COMCDSY = #{param.comcdsy}
AND MC2.COMCDSY = 'N'
WHERE MVO.VOUSEYN = 'Y' AND MVH.VHUSEYN = 'Y'
AND (MVH.PUBLCYN = 'Y' OR (MVH.PUBLCYN = 'N' AND MVH.DMWPLNM = #{param.dmwplnm}))
AND (MVH.PUBLCYN = 'Y' OR (MVH.PUBLCYN = 'N' AND MVH.DMWPLNM = REPLACE(LOWER(#{userData.schema}), '_', '-')))
AND MVH.VOWNKEY = #{param.vownkey}

