/* updateMowrma */
UPDATE ${userData.schema}.MOWRMA SET
	OWNAMLC = #{updateData.ownamlc}
	, OWNAMKO = #{updateData.ownamko}
	, OWNAMEN = #{updateData.ownamen}
	, OWNADDR = #{updateData.ownaddr}
	, OWNTELN = #{updateData.ownteln}
	, OWPOSBX = #{updateData.owposbx}
	, OWPOSCD = #{updateData.owposcd}
	, OWREPNM = #{updateData.owrepnm}
	, OWREPTL = #{updateData.owreptl}
	, OWREPEM = #{updateData.owrepem}
	, OWBLCTC = #{updateData.owblctc}
	, OWNEORD = #{updateData.owneord}
	, OWUSEYN = #{updateData.owuseyn}
	, LMODATE = to_char(NOW() ,'YYYYMMDD')
	, LMOTIME = to_char(NOW() ,'hh24miss')
	, LMOUSER = #{userData.useract}
	, UPDTCHK = #{updateData.updtchk} + 1
WHERE UPDTCHK = #{updateData.updtchk}


		AND OWNERKY = #{updateData.oldOwnerky}


		AND OWNERKY = #{updateData.ownerky}

