UPDATE ${userData.commonSchema}.MVHCMA
SET IFPRSTS = #{updateData.ifprsts},
	LMODATE = to_char(NOW() ,'YYYYMMDD'),
	LMOTIME = to_char(NOW() ,'hh24miss'),
	LMOUSER = #{userData.useract},
	UPDTCHK = UPDTCHK + 1
WHERE
	UPDTCHK = #{updateData.updtchk}
AND VOWNKEY = #{updateData.vownkey}
AND VEHICKY = #{updateData.vehicky}
